import React, { useState } from 'react';

const FarmerAdd = ({ onBack }) => {
  const [step, setStep] = useState(1);

  return (
    <div className="min-h-screen bg-white p-6">
      {/* Header with Back Button */}
      <div className="flex items-center mb-8">
        <button onClick={onBack} className="text-4xl mr-4">⬅️</button>
        <h1 className="text-2xl font-black text-green-800">Step {step} of 3</h1>
      </div>

      {/* STEP 1: PHOTO */}
      {step === 1 && (
        <div className="flex flex-col items-center">
          <p className="text-3xl font-bold mb-6 text-center">Take a Photo of Crop<br/>(फोटो काढा)</p>
          <div className="w-full aspect-square bg-gray-100 rounded-[40px] border-8 border-dashed border-gray-300 flex items-center justify-center text-8xl mb-10">
            📸
          </div>
          <button onClick={() => setStep(2)} className="w-full bg-green-600 text-white py-8 rounded-3xl text-3xl font-black shadow-xl">
            NEXT (पुढे जा)
          </button>
        </div>
      )}

      {/* STEP 2: QUANTITY */}
      {step === 2 && (
        <div className="flex flex-col">
          <p className="text-3xl font-bold mb-6 text-center">How much weight?<br/>(वजन किती?)</p>
          <input type="text" placeholder="e.g. 50 kg" className="w-full p-8 text-4xl rounded-3xl border-4 border-green-600 mb-10 text-center" />
          <button onClick={() => setStep(3)} className="w-full bg-green-600 text-white py-8 rounded-3xl text-3xl font-black shadow-xl">
            NEXT (पुढे जा)
          </button>
        </div>
      )}

      {/* STEP 3: PRICE */}
      {step === 3 && (
        <div className="flex flex-col">
          <p className="text-3xl font-bold mb-6 text-center">Price for total?<br/>(एकूण किंमत?)</p>
          <input type="number" placeholder="₹ 0.00" className="w-full p-8 text-5xl rounded-3xl border-4 border-orange-500 mb-10 text-center text-orange-600 font-bold" />
          <button onClick={() => alert("Crop Posted Successfully!")} className="w-full bg-orange-500 text-white py-10 rounded-3xl text-4xl font-black shadow-xl border-b-8 border-orange-800">
            FINISH (पूर्ण झाले)
          </button>
        </div>
      )}
    </div>
  );
};

export default FarmerAdd;
